/**
 * Tests for the WorktreeRemove exit-finalizer hook — M168 Phase 4 (#1914).
 *
 * Verifies that the matching worktree_links row is UPDATEd with
 * result_status='completed', the child's advisory state file is deleted,
 * and the worktree-events.jsonl log gets a 'worktree_done' entry.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, mkdirSync, mkdtempSync, readFileSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { DatabaseSync } from 'node:sqlite';

import { exitFinalizer } from '../../worktree/exit-finalizer.js';
import { NOOP_CTX } from '../../lib/context.js';
import { __resetDbForTests, openDb } from '../../lib/session-registry.js';
import { writeChildState, readChildState } from '../../lib/children-bus.js';
import type { HookInput } from '../../types.js';

function makeInput(sid: string, projectDir: string, worktreePath: string): HookInput {
  return {
    hook_event: 'WorktreeRemove',
    tool_name: '',
    session_id: sid,
    tool_input: {},
    project_dir: projectDir,
    worktree_path: worktreePath,
  } as HookInput;
}

/** Seed a parent session, child session w/ worktree_path, and a link row. */
function seedLink(
  parentSid: string,
  childSid: string,
  parentDir: string,
  worktreePath: string,
): void {
  const db = openDb();
  const now = Math.floor(Date.now() / 1000);
  db.prepare(
    `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat, status)
     VALUES (?, 1, ?, 'h', ?, ?, ?, 'running')`,
  ).run(parentSid, parentDir, parentDir, now, now);
  db.prepare(
    `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, worktree_path, started_at, last_heartbeat, status)
     VALUES (?, 2, ?, 'h', ?, ?, ?, ?, 'completed')`,
  ).run(childSid, worktreePath, parentDir, worktreePath, now, now);
  db.prepare(
    `INSERT INTO worktree_links (child_sid, parent_sid, purpose, created_at)
     VALUES (?, ?, ?, ?)`,
  ).run(childSid, parentSid, 'feature-work', now);
  db.close();
  __resetDbForTests();
}

describe('worktree/exit-finalizer (#1914)', () => {
  let projectDir: string;
  let dbPath: string;
  let prevEnv: string | undefined;

  beforeEach(() => {
    projectDir = mkdtempSync(join(tmpdir(), 'ork-exit-finalizer-'));
    dbPath = join(projectDir, 'sessions.db');
    prevEnv = process.env.ORK_SESSION_DB;
    process.env.ORK_SESSION_DB = dbPath;
    __resetDbForTests();
  });

  afterEach(() => {
    __resetDbForTests();
    if (prevEnv === undefined) delete process.env.ORK_SESSION_DB;
    else process.env.ORK_SESSION_DB = prevEnv;
    rmSync(projectDir, { recursive: true, force: true });
  });

  it('UPDATEs the worktree_links row with result_status="completed"', () => {
    const worktreePath = join(projectDir, '.worktrees', 'feature-a');
    seedLink('s-parent', 's-child', projectDir, worktreePath);

    const res = exitFinalizer(makeInput('s-parent', projectDir, worktreePath), NOOP_CTX);
    expect(res.continue).toBe(true);

    const db = new DatabaseSync(dbPath, { readOnly: true });
    const row = db
      .prepare('SELECT result_status, result_payload FROM worktree_links WHERE child_sid = ?')
      .get('s-child') as { result_status: string; result_payload: string };
    db.close();
    expect(row.result_status).toBe('completed');
    const parsed = JSON.parse(row.result_payload);
    expect(parsed.worktree_path).toBe(worktreePath);
    expect(typeof parsed.finished_at).toBe('number');
  });

  it('deletes the child advisory file under <parentDir>/.claude/state/children/', () => {
    const worktreePath = join(projectDir, '.worktrees', 'feature-b');
    seedLink('s-parent', 's-child-b', projectDir, worktreePath);

    // Drop a children/<sid>.json advisory file that should be cleaned up.
    writeChildState(projectDir, 's-child-b', { status: 'finishing' });
    expect(readChildState(projectDir, 's-child-b')).not.toBeNull();

    exitFinalizer(makeInput('s-parent', projectDir, worktreePath), NOOP_CTX);
    expect(readChildState(projectDir, 's-child-b')).toBeNull();
  });

  it('appends a worktree_done event to .claude/logs/worktree-events.jsonl', () => {
    const worktreePath = join(projectDir, '.worktrees', 'feature-c');
    seedLink('s-parent', 's-child-c', projectDir, worktreePath);

    // The event-logger uses ORCHESTKIT_PROJECT_DIR / CLAUDE_PROJECT_DIR
    // → project_dir is fetched via getProjectDir(). Set it explicitly.
    const prevProjectDir = process.env.CLAUDE_PROJECT_DIR;
    process.env.CLAUDE_PROJECT_DIR = projectDir;
    try {
      exitFinalizer(makeInput('s-parent', projectDir, worktreePath), NOOP_CTX);
    } finally {
      if (prevProjectDir === undefined) delete process.env.CLAUDE_PROJECT_DIR;
      else process.env.CLAUDE_PROJECT_DIR = prevProjectDir;
    }

    const logPath = join(projectDir, '.claude', 'logs', 'worktree-events.jsonl');
    expect(existsSync(logPath)).toBe(true);
    const lines = readFileSync(logPath, 'utf8').trim().split('\n');
    const entry = JSON.parse(lines[lines.length - 1]);
    expect(entry.event).toBe('worktree_done');
    expect(entry.worktree_path).toBe(worktreePath);
    expect(entry.rows_updated).toBeGreaterThanOrEqual(1);
    expect(entry.child_sids).toContain('s-child-c');
  });

  it('is a no-op when worktree_path is missing', () => {
    const input = {
      hook_event: 'WorktreeRemove',
      tool_name: '',
      session_id: 's-parent',
      tool_input: {},
      project_dir: projectDir,
    } as HookInput;
    const res = exitFinalizer(input, NOOP_CTX);
    expect(res.continue).toBe(true);
  });

  it('only UPDATEs rows whose result_status is still NULL (idempotent)', () => {
    const worktreePath = join(projectDir, '.worktrees', 'feature-d');
    seedLink('s-parent', 's-child-d', projectDir, worktreePath);

    // First call → marks as completed.
    exitFinalizer(makeInput('s-parent', projectDir, worktreePath), NOOP_CTX);
    // Manually pin a fixed payload so we can detect re-writes.
    const sentinel = JSON.stringify({ finished_at: 1, worktree_path: worktreePath, sentinel: true });
    const db = openDb();
    db.prepare(
      "UPDATE worktree_links SET result_payload = ? WHERE child_sid = 's-child-d'",
    ).run(sentinel);
    db.close();
    __resetDbForTests();

    // Second call should NOT overwrite (WHERE result_status IS NULL filter).
    exitFinalizer(makeInput('s-parent', projectDir, worktreePath), NOOP_CTX);

    const db2 = new DatabaseSync(dbPath, { readOnly: true });
    const row = db2
      .prepare('SELECT result_payload FROM worktree_links WHERE child_sid = ?')
      .get('s-child-d') as { result_payload: string };
    db2.close();
    expect(JSON.parse(row.result_payload).sentinel).toBe(true);
  });

  it('cleans up the pending-link marker from WorktreeCreate', () => {
    const slug = 'feature-e';
    const worktreePath = join(projectDir, '.worktrees', slug);
    seedLink('s-parent', 's-child-e', projectDir, worktreePath);

    // Pre-seed a pending marker (as enter-registrar would have written).
    const pendingDir = join(projectDir, '.claude', 'state', 'worktree-pending');
    mkdirSync(pendingDir, { recursive: true });
    const pendingPath = join(pendingDir, `${slug}.json`);
    writeFileSync(pendingPath, '{"parent_sid":"s-parent"}');
    expect(existsSync(pendingPath)).toBe(true);

    exitFinalizer(makeInput('s-parent', projectDir, worktreePath), NOOP_CTX);
    expect(existsSync(pendingPath)).toBe(false);
  });
});
